INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('8e5598cb-1d06-4ca4-80aa-63f262170a55', 'Đối với dạng bài Diagram/Flow Chart Labeling (Điền nhãn biểu đồ), mũi tên (arrows) trong biểu đồ đóng vai trò gì?', 'multiple_choice', '["Chỉ dùng để trang trí.","Chỉ ra thứ tự thời gian, quy trình hoặc dòng chảy thông tin của các sự kiện trong đoạn văn.","Thể hiện sự đối lập.","Chỉ ra vị trí của từ vựng khó."]', 'Chỉ ra thứ tự thời gian, quy trình hoặc dòng chảy thông tin của các sự kiện trong đoạn văn.', 'Biểu đồ quy trình (Flow chart) tóm tắt một quá trình diễn ra theo trình tự. Các mũi tên sẽ tương ứng với các từ chỉ thời gian trong bài như ''First'', ''Subsequently'', ''Finally''.'),
('8e5598cb-1d06-4ca4-80aa-63f262170a55', 'Bước đầu tiên quan trọng nhất trước khi quét thông tin (Scanning) cho bài Diagram Labeling là gì?', 'multiple_choice', '["Dịch toàn bộ bài đọc.","Nghiên cứu kỹ hình vẽ, đọc phần Tiêu đề của biểu đồ và dự đoán loại từ (Noun, Verb) cần điền vào các ô trống.","Khoanh lụi đáp án.","Đọc phần kết luận."]', 'Nghiên cứu kỹ hình vẽ, đọc phần Tiêu đề của biểu đồ và dự đoán loại từ (Noun, Verb) cần điền vào các ô trống.', 'Tiêu đề của biểu đồ là kim chỉ nam giúp bạn xác định ngay lập tức đoạn văn chứa nội dung miêu tả quy trình/cấu tạo của vật thể đó trong toàn bộ bài đọc.'),
('8e5598cb-1d06-4ca4-80aa-63f262170a55', 'Các từ vựng chỉ phương hướng và vị trí (Spatial vocabulary) nào thường xuyên xuất hiện nhất trong đoạn văn mô tả Diagram (ví dụ: sơ đồ máy móc)?', 'multiple_choice', '["Quickly, slowly, instantly.","Top, bottom, beneath, adjacent to, attached to.","Beautiful, ugly, large.","Yesterday, tomorrow, nowadays."]', 'Top, bottom, beneath, adjacent to, attached to.', 'Để chỉ ra các bộ phận của một cỗ máy hay cấu trúc sinh học, tác giả bắt buộc phải dùng các giới từ và cụm từ chỉ vị trí không gian để mô tả.'),
('e91d15db-9b5f-4ee6-be56-940e9a873316', 'Chiến lược quản lý thời gian kinh điển nhất cho 3 bài đọc trong 60 phút của IELTS Academic Reading là gì?', 'multiple_choice', '["Dành 30 phút cho Passage 1 vì nó dễ nhất.","Chia đều thời gian: Passage 1 (15 phút) - Passage 2 (20 phút) - Passage 3 (25 phút) do độ khó tăng dần.","Đọc từ cuối lên đầu.","Vừa đọc vừa chép đáp án ra giấy nháp."]', 'Chia đều thời gian: Passage 1 (15 phút) - Passage 2 (20 phút) - Passage 3 (25 phút) do độ khó tăng dần.', 'Độ khó, độ dài và tính trừu tượng của văn bản tăng mạnh từ Passage 1 đến 3. Bạn phải tiết kiệm thời gian ở đoạn đầu để xử lý các câu hỏi suy luận khó ở đoạn cuối.'),
('e91d15db-9b5f-4ee6-be56-940e9a873316', 'Nếu bạn gặp một câu hỏi quá khó và không tìm thấy thông tin sau 2 phút tìm kiếm, bạn nên làm gì?', 'multiple_choice', '["Đọc lại bài văn từ đầu đến cuối.","Dừng lại và suy nghĩ cho đến khi tìm ra.","Bỏ qua (Skip), đánh dấu lại và tiếp tục làm các câu khác, sau đó quay lại đoán (Guess) nếu còn thời gian.","Bỏ trống hoàn toàn không điền vào Answer Sheet."]', 'Bỏ qua (Skip), đánh dấu lại và tiếp tục làm các câu khác, sau đó quay lại đoán (Guess) nếu còn thời gian.', 'Tất cả các câu hỏi đều có điểm số bằng nhau (1 điểm). Việc tốn 5 phút cho một câu hỏi khó là một sự lãng phí chiến lược nghiêm trọng.'),
('e91d15db-9b5f-4ee6-be56-940e9a873316', 'Khi nhận được đề thi Reading, điều ĐẦU TIÊN bạn nên làm trước khi đọc từng chữ trong Passage là gì?', 'multiple_choice', '["Đọc lướt (Skim) Tiêu đề (Title), Tiêu đề phụ (Subtitle), Hình ảnh minh họa và quét qua các Dạng câu hỏi được yêu cầu.","Đọc kỹ câu đầu tiên của đoạn 1.","Dịch các từ khó.","Bắt tay vào làm dạng True/False ngay lập tức."]', 'Đọc lướt (Skim) Tiêu đề (Title), Tiêu đề phụ (Subtitle), Hình ảnh minh họa và quét qua các Dạng câu hỏi được yêu cầu.', 'Việc này giúp não bộ ''khởi động'' (warm-up), hình dung bối cảnh chủ đề (Context) và lên chiến thuật nên xử lý nhóm câu hỏi nào trước (ví dụ: làm Name Matching trước TFNG).'),
('c094ea19-54f7-4c4b-a275-68474ecc9801', 'Nội dung của Section 1 trong bài thi IELTS General Training Reading thường tập trung vào chủ đề gì?', 'multiple_choice', '["Các bài nghiên cứu khoa học chuyên sâu.","Những thông tin thực tế phục vụ cho sự sinh tồn và giao tiếp hàng ngày ở môi trường nói tiếng Anh (ví dụ: quảng cáo, thời khóa biểu, tờ rơi).","Các bài tiểu luận triết học.","Tiểu sử của các nhà văn nổi tiếng."]', 'Những thông tin thực tế phục vụ cho sự sinh tồn và giao tiếp hàng ngày ở môi trường nói tiếng Anh (ví dụ: quảng cáo, thời khóa biểu, tờ rơi).', 'Section 1 của bài thi GT (General Training) thiết kế các văn bản ngắn (Short factual texts) mô phỏng chính xác những gì một người nhập cư sẽ đọc hàng ngày.'),
('c094ea19-54f7-4c4b-a275-68474ecc9801', 'Dạng bài điền từ vào chỗ trống (Fill in the blanks) trong Section 1 GT thường yêu cầu kỹ năng nào nhất?', 'multiple_choice', '["Suy luận ý nghĩa sâu xa.","Scanning (Quét nhanh) để tìm ra các con số, ngày tháng, địa điểm hoặc giá tiền chính xác.","Tóm tắt đại ý.","Đọc hiểu cấu trúc ngữ pháp phức tạp."]', 'Scanning (Quét nhanh) để tìm ra các con số, ngày tháng, địa điểm hoặc giá tiền chính xác.', 'Vì các văn bản mang tính thông tin thực tế (như bảng giá, lịch trình tàu), kỹ năng dò tìm dữ kiện cụ thể (Scanning) là chìa khóa ăn điểm tuyệt đối.'),
('c094ea19-54f7-4c4b-a275-68474ecc9801', 'Văn bản trong Section 1 GT thường có bố cục như thế nào để dễ đọc?', 'multiple_choice', '["Một đoạn văn bản đặc chữ dài 3 trang.","Sử dụng rất nhiều Bullet points (gạch đầu dòng), in đậm, in nghiêng và các đoạn văn cực ngắn.","Không có dấu chấm phẩy.","Viết dưới dạng thơ ca."]', 'Sử dụng rất nhiều Bullet points (gạch đầu dòng), in đậm, in nghiêng và các đoạn văn cực ngắn.', 'Bố cục chia nhỏ (chunking) của tờ rơi hoặc quảng cáo giúp thí sinh dễ dàng khoanh vùng vị trí đáp án bằng cách nhìn vào các tiêu đề phụ.'),
('4ef03de9-ade1-4da3-bee3-db63d7934c1c', 'Các văn bản ''Hướng dẫn & Quy định'' (Guidelines & Regulations) trong Section 1 GT thường sử dụng cấu trúc ngữ pháp nào nhiều nhất?', 'multiple_choice', '["Câu điều kiện loại 3.","Câu mệnh lệnh (Imperatives) và Động từ khuyết thiếu mang tính bắt buộc (must, have to, should).","Thì tương lai hoàn thành.","Câu bị động phức tạp."]', 'Câu mệnh lệnh (Imperatives) và Động từ khuyết thiếu mang tính bắt buộc (must, have to, should).', 'Ví dụ: ''Passengers must present their tickets'' hoặc ''Do not leave luggage unattended''. Việc hiểu mức độ bắt buộc của Modal verbs giúp trả lời dạng TFNG.'),
('4ef03de9-ade1-4da3-bee3-db63d7934c1c', 'Trong một bài đọc về Thể lệ trả hàng (Return Policy), nếu có câu hỏi True/False/Not Given, từ khóa ''Only'' (Chỉ) trong văn bản cần được chú ý như thế nào?', 'multiple_choice', '["Nó không quan trọng.","Nó thường là ''bẫy'' giới hạn điều kiện. Ví dụ: ''Refunds are ONLY given within 14 days''.","Nó luôn luôn có nghĩa là False.","Nó có nghĩa là bạn được làm mọi thứ."]', 'Nó thường là ''bẫy'' giới hạn điều kiện. Ví dụ: ''Refunds are ONLY given within 14 days''.', 'Các từ mang tính loại trừ (exclusive words) như ''only'', ''solely'', ''strictly'' định hình chính xác phạm vi áp dụng của quy định.'),
('4ef03de9-ade1-4da3-bee3-db63d7934c1c', 'Dạng bài ''Matching paragraphs with information'' trong bối cảnh các quy định thường hỏi về điều gì?', 'multiple_choice', '["Tìm xem quy định nào nói về hình phạt, quy định nào nói về lợi ích, v.v.","Tìm tên tác giả.","Phân tích cảm xúc người viết.","Tìm lỗi chính tả."]', 'Tìm xem quy định nào nói về hình phạt, quy định nào nói về lợi ích, v.v.', 'Thí sinh phải nối các tình huống của khách hàng (ví dụ: ''You lost your receipt'') với đoạn văn chứa quy định giải quyết tình huống đó.'),
('c4e17321-7ca9-41ce-8007-2895e71c77a2', 'Nội dung của Section 2 trong bài thi General Training Reading tập trung vào chủ đề cốt lõi nào?', 'multiple_choice', '["Môi trường sinh thái.","Cuộc sống học đường.","Môi trường làm việc và các vấn đề công sở (Workplace survival).","Du lịch quốc tế."]', 'Môi trường làm việc và các vấn đề công sở (Workplace survival).', 'Section 2 GT được thiết kế để kiểm tra khả năng đọc hiểu các văn bản nội bộ công ty như: Hợp đồng lao động, Sổ tay nhân viên (Staff manual), hay Quy trình khiếu nại.'),
('c4e17321-7ca9-41ce-8007-2895e71c77a2', 'Một ''Job Description'' (Bản mô tả công việc) trong bài thi thường chứa các thông tin nào để thí sinh phân tích?', 'multiple_choice', '["Giá cả hàng hóa.","Nhiệm vụ hàng ngày, Yêu cầu trình độ/kỹ năng (Qualifications), và Phúc lợi (Benefits/Perks).","Lịch sử hình thành công ty.","Danh sách khách hàng."]', 'Nhiệm vụ hàng ngày, Yêu cầu trình độ/kỹ năng (Qualifications), và Phúc lợi (Benefits/Perks).', 'Câu hỏi thường đưa ra một danh sách các ứng viên và yêu cầu bạn ''Match'' ứng viên đó với vị trí công việc phù hợp dựa trên kinh nghiệm của họ.'),
('c4e17321-7ca9-41ce-8007-2895e71c77a2', 'Thuật ngữ ''Remuneration'' xuất hiện trong văn bản công việc của IELTS mang ý nghĩa gì?', 'multiple_choice', '["Sự sa thải.","Sự trả thù.","Sự đền bù tài chính, tiền lương và các phúc lợi cho người lao động (Compensation/Pay).","Khóa đào tạo nhân viên."]', 'Sự đền bù tài chính, tiền lương và các phúc lợi cho người lao động (Compensation/Pay).', 'Đây là từ vựng formal cực kỳ phổ biến trong các văn bản nhân sự (HR). Nếu câu hỏi nhắc đến ''Salary/Wages'', bạn phải quét tìm từ ''Remuneration'' trong bài.'),
('bd6b7329-80bd-4a2e-87be-a5051ebde26b', 'Khi đọc một văn bản về ''Cơ sở vật chất đào tạo'' (Training facilities) trong Section 2, yếu tố Paraphrase nào thường được áp dụng nhất?', 'multiple_choice', '["Giữ nguyên 100% từ vựng.","Biến đổi từ ngữ chỉ Tần suất (ví dụ: ''Annually'' trong bài đổi thành ''Once a year'' trong câu hỏi).","Sử dụng ngôn ngữ ký hiệu.","Chỉ dùng hình ảnh không có chữ."]', 'Biến đổi từ ngữ chỉ Tần suất (ví dụ: ''Annually'' trong bài đổi thành ''Once a year'' trong câu hỏi).', 'Các bài về dịch vụ và đào tạo thường xuyên paraphrase các con số, thời gian biểu và điều kiện đăng ký tham gia khóa học.'),
('bd6b7329-80bd-4a2e-87be-a5051ebde26b', 'Đoạn văn ''Grievance Procedure'' (Quy trình khiếu nại) trong sổ tay nhân viên thường được tổ chức theo cấu trúc nào?', 'multiple_choice', '["Miêu tả ngoại hình.","Liệt kê các bước thực hiện theo trình tự thời gian (Step-by-step sequential order).","So sánh và đối chiếu.","Sử dụng phép ẩn dụ văn học."]', 'Liệt kê các bước thực hiện theo trình tự thời gian (Step-by-step sequential order).', 'Vì là quy trình (Procedure), văn bản thường có các mốc như Step 1 (Verbal warning), Step 2 (Written warning). Các dạng bài Flow-chart completion rất hay xuất hiện ở đây.'),
('bd6b7329-80bd-4a2e-87be-a5051ebde26b', 'Từ ''Mandatory'' trong thông báo tham gia khóa huấn luyện an toàn lao động có ý nghĩa gì đối với nhân viên?', 'multiple_choice', '["Tùy chọn, ai thích thì tham gia.","Có thể đăng ký học vào năm sau.","Bắt buộc, không có ngoại lệ (Compulsory/Required).","Khóa học có tính phí."]', 'Bắt buộc, không có ngoại lệ (Compulsory/Required).', 'Đây là từ vựng chìa khóa. Nếu câu hỏi nói ''Staff have the option to attend...'', mà văn bản dùng ''Mandatory'', thì đáp án chắc chắn là False.');